    mode: { kind: "play" },
    recentEvents: [],
    abortedBySignal: false,
  };

  const onSigint = (): void => {
    context.abortedBySignal = true;
  };

  if (options.interactive !== false && process.stdin.isTTY && options.input === undefined) {
    process.once("SIGINT", onSigint);
  }

  try {
    paint(context);

    while (context.session.getState().run.terminalStatus === ACTIVE_TERMINAL_STATUS) {
      const key = await input.readKey();

      if (key === null) {
        if (context.abortedBySignal) {
          stepRecorded(context, { kind: "abort" });
        }
        break;
      }

      if (key === "Ctrl-C") {
        context.abortedBySignal = true;
        stepRecorded(context, { kind: "abort" });
        break;
      }

      const keepPlaying = await handleKey(context, key);
      paint(context);

      if (!keepPlaying) {
        break;
      }
    }
  } finally {
    input.close();
    process.off("SIGINT", onSigint);
  }

  const summary = summarizeRun(context.session.getState());
  const summaryText = formatRunSummary(summary, context.session.tracePath);
  sink.write("");
  sink.write(summaryText);

  return {
    summary,
    tracePath: context.session.tracePath,
    output: context.lines.join("\n"),
  };
};

const createSession = (options: {
  readonly seed: string;
  readonly provider: FloorContentProvider;
  readonly recordTrace: boolean;
  readonly createdAt: string;
  readonly traceRootDir?: string;
  readonly traceFs?: TraceFsAdapter;
}): PlaySession => {
  const started = startRun(options.seed, options.provider);
  if (!started.ok) {
    throw new Error(started.error.message);
  }

  let state = started.state;

  const baseStep = (action: RunAction): RunStepSlice => {
    const result = stepPlayerAction(state, action, options.provider);
    if (!result.ok) {
      throw new Error(result.error.message);
    }

    state = result.state;
    return {
      state: result.state,
      events: result.events,
    };
  };

  if (!options.recordTrace) {
    return {
      getState: () => state,
      setState: (next) => {
        state = next;
      },
      step: baseStep,
      tracePath: null,
    };
  }

  const traceOptions: TraceRecorderOptions = {
    seed: options.seed,
    createdAt: options.createdAt,
    modelId: "none",
    contentRef: FALLBACK_CONTENT_REF,
    writer: createFileTraceWriter({
      runId: traceRunId(options.seed, options.createdAt),
      rootDir: options.traceRootDir,
      ...(options.traceFs === undefined ? {} : { fs: options.traceFs }),
    }),
  };

  const recorded: RecordedSession<RunAction, RunEvent> = record(
    {
      get state() {
        return state;
      },
      step: baseStep,
    },
    traceOptions,
  );

  return {
    getState: () => recorded.state,

    source: ready.source,
    depth: ready.depth,
  };
};

const resolveFloor = async (
  depth: number,
  seed: string,
): Promise<ServedFloor> => {
  const ready = consumeReady(depth);
  if (ready !== null) {
    return servedFromReady(ready, seed);
  }

  if (inFlightSlot?.depth === depth) {
    const waited = await waitForReadySlot(depth, inFlightSlot.startedAtMs);
    if (waited !== null) {
      return servedFromReady(waited, seed);
    }

    return serveFallback(depth, seed);
  }

  startPrefetch(depth, emptyTrace(options.runId, options.seed));
  return serveFallback(depth, seed);
};

const onFloorEnter = (depth: number, trace: ParsedTrace): void => {
  currentFloorDepth = depth;
  startPrefetch(depth + 1, trace);
};

const getFloor = (depth: number, seed: string): FloorContent => {
  const ready = consumeReady(depth);
  if (ready !== null) {
    servedSources.set(depth, ready.source);
    startPrefetch(depth + 1, emptyTrace(options.runId, options.seed));
    return {
      ...ready.content,
      params: {
        ...ready.content.params,
        seed,
      },
    };
  }

  if (inFlightSlot?.depth === depth) {
    const remainingMs = Math.max(
      0,
      stairsCapMs - (clock() - inFlightSlot.startedAtMs),
    );
    const resolved = waitForPromiseSync(
      inFlightSlot.promise.then(() => consumeReady(depth)),
      remainingMs,
      clock,
    );

    if (resolved !== null) {
      servedSources.set(depth, resolved.source);
      startPrefetch(depth + 1, emptyTrace(options.runId, options.seed));
      return {
        ...resolved.content,
        params: {
          ...resolved.content.params,
          seed,
        },
      };
    }

    const served = serveFallback(depth, seed);
    return served.content;
  }

  startPrefetch(depth, emptyTrace(options.runId, options.seed));
  return serveFallback(depth, seed).content;
};

