      startedAtMs: inFlightSlot.startedAtMs,

  constructor(controller: PrefetchController) {
    this.controller = controller;
  }

  getFloor(depth: number, seed: string): FloorContent {
    return this.controller.getFloor(depth, seed);
  }
}

