  if (!isSafeRunId(runId)) {
    return {
      status: 400,
      payload: { ok: false, error: "invalid_run_id" },
    };
  }

  try {
    return {
      status: 200,
      payload: {
        ok: true,
        action: "load",
        model: loadArtifactViewerModel(runId, options),
      },
    };
  } catch (error) {
    return {
      status: 404,
      payload: {
        ok: false,
        error: error instanceof Error ? error.message : String(error),
      },
    };
  }
};

