const withArtifactRunId = (
  registry: RunControllerRegistry,
  artifactRunId: string
): RunControllerRegistry => ({
  get: (runId) => registry.get(runId),
  getOrCreate: (runId, options) =>
    registry.getOrCreate(runId, { ...options, runId: artifactRunId }),
  remove: (runId) => registry.remove(runId)
});

export const createWebTransportState = (
  options: WebTransportStateOptions = {}
): WebTransportState => {
  const seed = options.seed ?? SEED;
  const createdAt = options.createdAt ?? SERVER_STARTED_AT;
  const artifactRunId = traceRunId(seed, createdAt);
  const registry = withArtifactRunId(
    createRunControllerRegistry(),
    artifactRunId
  );
  const artifacts = {
    fs: options.artifacts?.fs ?? new MemoryArtifactFs(),
    rootDir: options.artifacts?.rootDir ?? ROOT_DIR
  };

  return {
    artifacts,
    seed,
    createdAt,
    artifactRunId,
    handlers: createTransportHandlers(registry, {
      seed,
      modelId: USE_AMBIENT ? "ambient-web-transport" : MODEL_ID,
      provider: createWebProvider(),
      gate2: passingGate2(),
      artifacts,
      now: () => createdAt
    })
  };
};

